import React, { useState } from 'react'
import { Link } from 'react-router-dom'
import AddDecoPage from './AddDecoPage'
import RoomInfo from './RoomInfo'



export default function EditRoom(props) {
  const [addPage, setAddPage] = useState(false)
  const [buttonText, setButtonText] = useState("")
  let addItem = (newItemName) => {
      props.addNewDeco(props.name, newItemName)
    }

  
    let whatPageToShow=()=>{
      if(addPage){
        setButtonText("Add item")
        return <RoomInfo room={props.room}   addNewDeco={props.addNewDeco} turnOnOrOff={props.turnOnOrOff}/>
      }
      else {
        setButtonText("to the room info")
        return <AddDecoPage/>
      }

    }

  return (
    <div>
        {whatPageToShow()}
      <button onClick={setAddPage(!addPage)}>Add Item</button>
      <Link to={"/myrooms"}><button>back to my rooms list</button></Link>
      <button onClick={addItem}>{buttonText}</button>



    </div>
  )
}
